// And groups predicates with the AND operator between them.
func And(predicates ...predicate.PartnerLink) predicate.PartnerLink {
	return predicate.PartnerLink(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.PartnerLink) predicate.PartnerLink {
	return predicate.PartnerLink(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.PartnerLink) predicate.PartnerLink {
	return predicate.PartnerLink(sql.NotPredicates(p))
}
